mapper.select:
SELECT 
  FROM t_ai_agent
 WHERE deleted_at IS NULL
   AND owner_account_sn = #{ownerAccountSn}

   AND status = #{status}

 ORDER BY started_at DESC

SELECT 
  FROM t_ai_agent
 WHERE agent_id = #{agentId}
   AND owner_account_sn = #{ownerAccountSn}
   AND deleted_at IS NULL

mapper.delete:
DELETE FROM t_ai_agent
 WHERE agent_id = #{agentId}
   AND owner_account_sn = #{ownerAccountSn}

mapper.update:
UPDATE t_ai_agent
   SET status = #{status},
       updated_at = NOW()

      ,context_pct = #{contextPct}

 WHERE agent_id = #{agentId}
   AND deleted_at IS NULL

UPDATE t_ai_agent
   SET workspace_dir = #{workspaceDir},
       updated_at    = NOW()
 WHERE agent_id = #{agentId}
   AND owner_account_sn = #{ownerAccountSn}
   AND deleted_at IS NULL
